import{_ as n,o as s,c as t,a4 as l}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"化学计算套路","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Review-Routine-008-化学计算套路-V1.0-20260405.md","filePath":"chemistry/Chem-Review-Routine-008-化学计算套路-V1.0-20260405.md"}'),e={name:"chemistry/Chem-Review-Routine-008-化学计算套路-V1.0-20260405.md"};function i(p,a,o,r,h,d){return s(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="化学计算套路" tabindex="-1">化学计算套路 <a class="header-anchor" href="#化学计算套路" aria-label="Permalink to &quot;化学计算套路&quot;">​</a></h1><p><strong>高考化学必考题型——计算题解题技巧</strong></p><hr><h2 id="题型认知" tabindex="-1">题型认知 <a class="header-anchor" href="#题型认知" aria-label="Permalink to &quot;题型认知&quot;">​</a></h2><h3 id="常见计算类型" tabindex="-1">常见计算类型 <a class="header-anchor" href="#常见计算类型" aria-label="Permalink to &quot;常见计算类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:center;">分值</th><th style="text-align:center;">难度</th></tr></thead><tbody><tr><td style="text-align:center;">物质的量计算</td><td style="text-align:center;">2-4分</td><td style="text-align:center;">⭐⭐</td></tr><tr><td style="text-align:center;">化学方程式计算</td><td style="text-align:center;">4-6分</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">化学平衡计算</td><td style="text-align:center;">4-6分</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">电化学计算</td><td style="text-align:center;">2-4分</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">纯度/产率计算</td><td style="text-align:center;">2-4分</td><td style="text-align:center;">⭐⭐</td></tr></tbody></table><h3 id="计算题特点" tabindex="-1">计算题特点 <a class="header-anchor" href="#计算题特点" aria-label="Permalink to &quot;计算题特点&quot;">​</a></h3><ul><li>步骤分很重要，不能只写答案</li><li>单位必须写，有效数字要注意</li><li>常考「守恒法」简化计算</li></ul><hr><h2 id="核心公式速查" tabindex="-1">核心公式速查 <a class="header-anchor" href="#核心公式速查" aria-label="Permalink to &quot;核心公式速查&quot;">​</a></h2><h3 id="化学计量关系" tabindex="-1">化学计量关系 <a class="header-anchor" href="#化学计量关系" aria-label="Permalink to &quot;化学计量关系&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n = m/M = V/Vm = cV = N/Nₐ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>m：质量（g）</span></span>
<span class="line"><span>M：摩尔质量（g/mol）</span></span>
<span class="line"><span>V：气体体积（L，标况）</span></span>
<span class="line"><span>Vm：22.4 L/mol（标况气体）</span></span>
<span class="line"><span>c：物质的量浓度（mol/L）</span></span>
<span class="line"><span>V：溶液体积（L）</span></span>
<span class="line"><span>N：粒子数</span></span>
<span class="line"><span>Nₐ：6.02×10²³ mol⁻¹</span></span></code></pre></div><h3 id="浓度计算" tabindex="-1">浓度计算 <a class="header-anchor" href="#浓度计算" aria-label="Permalink to &quot;浓度计算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>稀释公式：c₁V₁ = c₂V₂</span></span>
<span class="line"><span></span></span>
<span class="line"><span>混合公式：c混V混 = c₁V₁ + c₂V₂</span></span></code></pre></div><h3 id="产率-纯度" tabindex="-1">产率/纯度 <a class="header-anchor" href="#产率-纯度" aria-label="Permalink to &quot;产率/纯度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>产率 = (实际产量/理论产量) × 100%</span></span>
<span class="line"><span>纯度 = (纯品质量/样品质量) × 100%</span></span></code></pre></div><h3 id="电化学计算" tabindex="-1">电化学计算 <a class="header-anchor" href="#电化学计算" aria-label="Permalink to &quot;电化学计算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q = I × t = n × F × z</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Q：电量（C）</span></span>
<span class="line"><span>I：电流（A）</span></span>
<span class="line"><span>t：时间（s）</span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>F：96500 C/mol（法拉第常数）</span></span>
<span class="line"><span>z：转移电子数</span></span></code></pre></div><hr><h2 id="解题技巧" tabindex="-1">解题技巧 <a class="header-anchor" href="#解题技巧" aria-label="Permalink to &quot;解题技巧&quot;">​</a></h2><h3 id="技巧1-物质的量是桥梁" tabindex="-1">技巧1：物质的量是桥梁 <a class="header-anchor" href="#技巧1-物质的量是桥梁" aria-label="Permalink to &quot;技巧1：物质的量是桥梁&quot;">​</a></h3><p><strong>核心思想</strong>：把所有物理量都转化为物质的量，再进行计算。</p><p><strong>示例</strong>：</p><ul><li>已知：9 g水</li><li>求：含多少个水分子？</li><li>解： <ul><li>n = m/M = 9 g / 18 g/mol = 0.5 mol</li><li>N = n × Nₐ = 0.5 × 6.02×10²³ = 3.01×10²³</li></ul></li></ul><h3 id="技巧2-守恒法-最常用" tabindex="-1">技巧2：守恒法（最常用） <a class="header-anchor" href="#技巧2-守恒法-最常用" aria-label="Permalink to &quot;技巧2：守恒法（最常用）&quot;">​</a></h3><h4 id="质量守恒" tabindex="-1">质量守恒 <a class="header-anchor" href="#质量守恒" aria-label="Permalink to &quot;质量守恒&quot;">​</a></h4><p>化学反应前后总质量不变。</p><p><strong>应用</strong>：</p><ul><li>根据反应前后质量差求气体质量</li><li>复杂反应中追踪某元素</li></ul><h4 id="元素守恒" tabindex="-1">元素守恒 <a class="header-anchor" href="#元素守恒" aria-label="Permalink to &quot;元素守恒&quot;">​</a></h4><p>反应前后某元素的原子总数不变。</p><p><strong>示例</strong>：</p><ul><li>Na₂CO₃与HCl反应，无论生成NaHCO₃还是CO₂</li><li>Na元素始终在溶液中，可用Na守恒计算</li></ul><h4 id="电荷守恒" tabindex="-1">电荷守恒 <a class="header-anchor" href="#电荷守恒" aria-label="Permalink to &quot;电荷守恒&quot;">​</a></h4><p>溶液中正负电荷总数相等。</p><p><strong>应用</strong>：</p><ul><li>离子浓度计算</li><li>电荷平衡方程式</li></ul><h4 id="电子守恒-氧化还原" tabindex="-1">电子守恒（氧化还原） <a class="header-anchor" href="#电子守恒-氧化还原" aria-label="Permalink to &quot;电子守恒（氧化还原）&quot;">​</a></h4><p>氧化剂得电子总数 = 还原剂失电子总数。</p><p><strong>示例</strong>：</p><ul><li>Cu与HNO₃反应</li><li>Cu失电子：Cu → Cu²⁺ + 2e⁻</li><li>N得电子：NO₃⁻ → NO₂（或NO）</li><li>得失电子数相等</li></ul><h3 id="技巧3-差量法" tabindex="-1">技巧3：差量法 <a class="header-anchor" href="#技巧3-差量法" aria-label="Permalink to &quot;技巧3：差量法&quot;">​</a></h3><p><strong>原理</strong>：利用反应前后某物理量的差值进行计算。</p><p><strong>适用场景</strong>：</p><ul><li>气体体积变化</li><li>固体质量变化</li><li>溶液质量变化</li></ul><p><strong>示例</strong>：</p><ul><li>2Na₂O₂ + 2CO₂ = 2Na₂CO₃ + O₂</li><li>Δm = 2×106 - 2×78 = 56 g（每消耗2 mol CO₂，固体增重56 g）</li></ul><h3 id="技巧4-关系式法" tabindex="-1">技巧4：关系式法 <a class="header-anchor" href="#技巧4-关系式法" aria-label="Permalink to &quot;技巧4：关系式法&quot;">​</a></h3><p><strong>原理</strong>：找出已知量与未知量之间的直接关系式。</p><p><strong>示例</strong>：</p><ul><li>工业制硫酸：FeS₂ → 2SO₂ → 2SO₃ → 2H₂SO₄</li><li>关系式：FeS₂ ~ 2H₂SO₄</li></ul><h3 id="技巧5-极值法-范围计算" tabindex="-1">技巧5：极值法（范围计算） <a class="header-anchor" href="#技巧5-极值法-范围计算" aria-label="Permalink to &quot;技巧5：极值法（范围计算）&quot;">​</a></h3><p><strong>原理</strong>：假设反应完全向某一方向进行，求极值，确定范围。</p><p><strong>应用</strong>：</p><ul><li>混合物计算</li><li>过量问题</li></ul><hr><h2 id="典型题型详解" tabindex="-1">典型题型详解 <a class="header-anchor" href="#典型题型详解" aria-label="Permalink to &quot;典型题型详解&quot;">​</a></h2><h3 id="题型1-物质的量综合计算" tabindex="-1">题型1：物质的量综合计算 <a class="header-anchor" href="#题型1-物质的量综合计算" aria-label="Permalink to &quot;题型1：物质的量综合计算&quot;">​</a></h3><p><strong>例题</strong>： 标准状况下，11.2 L CO₂的物质的量是多少？质量是多少？含多少个CO₂分子？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n = V/Vm = 11.2 L / 22.4 L/mol = 0.5 mol</span></span>
<span class="line"><span>m = n × M = 0.5 mol × 44 g/mol = 22 g</span></span>
<span class="line"><span>N = n × Nₐ = 0.5 × 6.02×10²³ = 3.01×10²³</span></span></code></pre></div><h3 id="题型2-化学方程式计算" tabindex="-1">题型2：化学方程式计算 <a class="header-anchor" href="#题型2-化学方程式计算" aria-label="Permalink to &quot;题型2：化学方程式计算&quot;">​</a></h3><p><strong>例题</strong>： 含杂质10%的Zn 13 g与足量稀H₂SO₄反应，求生成的H₂在标况下的体积。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>纯Zn质量：13 g × (1-10%) = 11.7 g</span></span>
<span class="line"><span>Zn的物质的量：n = 11.7 g / 65 g/mol = 0.18 mol</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Zn + H₂SO₄ = ZnSO₄ + H₂↑</span></span>
<span class="line"><span>1 mol                    1 mol</span></span>
<span class="line"><span>0.18 mol                 n(H₂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n(H₂) = 0.18 mol</span></span>
<span class="line"><span>V(H₂) = 0.18 mol × 22.4 L/mol = 4.032 L</span></span></code></pre></div><h3 id="题型3-化学平衡计算-三段式" tabindex="-1">题型3：化学平衡计算（三段式） <a class="header-anchor" href="#题型3-化学平衡计算-三段式" aria-label="Permalink to &quot;题型3：化学平衡计算（三段式）&quot;">​</a></h3><p><strong>例题</strong>： N₂ + 3H₂ ⇌ 2NH₃，起始时N₂为1 mol，H₂为3 mol，平衡时NH₃为0.5 mol，求： (1) N₂的转化率；(2) 平衡常数K。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         N₂    +    3H₂    ⇌    2NH₃</span></span>
<span class="line"><span>起始     1          3            0</span></span>
<span class="line"><span>转化    -0.25      -0.75        +0.5</span></span>
<span class="line"><span>平衡     0.75       2.25         0.5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(1) 转化率 = (0.25/1) × 100% = 25%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) 假设体积为V L</span></span>
<span class="line"><span>K = [NH₃]² / ([N₂][H₂]³) </span></span>
<span class="line"><span>  = (0.5/V)² / ((0.75/V) × (2.25/V)³)</span></span>
<span class="line"><span>  = ...（具体计算略）</span></span></code></pre></div><h3 id="题型4-氧化还原计算-电子守恒" tabindex="-1">题型4：氧化还原计算（电子守恒） <a class="header-anchor" href="#题型4-氧化还原计算-电子守恒" aria-label="Permalink to &quot;题型4：氧化还原计算（电子守恒）&quot;">​</a></h3><p><strong>例题</strong>： 3.2 g Cu与足量浓HNO₃反应，求生成的NO₂在标况下的体积。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cu失电子：Cu → Cu²⁺ + 2e⁻</span></span>
<span class="line"><span>n(Cu) = 3.2 g / 64 g/mol = 0.05 mol</span></span>
<span class="line"><span>失电子数 = 0.05 × 2 = 0.1 mol</span></span>
<span class="line"><span></span></span>
<span class="line"><span>N得电子：NO₃⁻ + 2H⁺ + e⁻ = NO₂↑ + H₂O</span></span>
<span class="line"><span>每生成1 mol NO₂，得1 mol电子</span></span>
<span class="line"><span></span></span>
<span class="line"><span>根据电子守恒：</span></span>
<span class="line"><span>n(NO₂) = 0.1 mol</span></span>
<span class="line"><span>V(NO₂) = 0.1 mol × 22.4 L/mol = 2.24 L</span></span></code></pre></div><h3 id="题型5-电化学计算" tabindex="-1">题型5：电化学计算 <a class="header-anchor" href="#题型5-电化学计算" aria-label="Permalink to &quot;题型5：电化学计算&quot;">​</a></h3><p><strong>例题</strong>： 用惰性电极电解CuSO₄溶液，通电2 A电流30分钟，求阴极析出Cu的质量。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q = I × t = 2 A × 30 × 60 s = 3600 C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阴极反应：Cu²⁺ + 2e⁻ = Cu</span></span>
<span class="line"><span>每析出1 mol Cu，转移2 mol电子</span></span>
<span class="line"><span></span></span>
<span class="line"><span>n(e⁻) = Q/F = 3600 C / 96500 C/mol = 0.0373 mol</span></span>
<span class="line"><span>n(Cu) = n(e⁻)/2 = 0.01865 mol</span></span>
<span class="line"><span>m(Cu) = 0.01865 mol × 64 g/mol = 1.19 g</span></span></code></pre></div><hr><h2 id="常见错误提醒" tabindex="-1">常见错误提醒 <a class="header-anchor" href="#常见错误提醒" aria-label="Permalink to &quot;常见错误提醒&quot;">​</a></h2><h3 id="单位错误" tabindex="-1">单位错误 <a class="header-anchor" href="#单位错误" aria-label="Permalink to &quot;单位错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">错误</th><th style="text-align:left;">正确</th></tr></thead><tbody><tr><td style="text-align:left;">22.4 L/mol用于液体</td><td style="text-align:left;">只用于标况气体</td></tr><tr><td style="text-align:left;">mL没有换算成L</td><td style="text-align:left;">计算前统一单位</td></tr><tr><td style="text-align:left;">时间单位混乱（min和s混用）</td><td style="text-align:left;">统一换算成秒</td></tr></tbody></table><h3 id="计算错误" tabindex="-1">计算错误 <a class="header-anchor" href="#计算错误" aria-label="Permalink to &quot;计算错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">错误</th><th style="text-align:left;">正确</th></tr></thead><tbody><tr><td style="text-align:left;">化学计量数比搞错</td><td style="text-align:left;">仔细审题，列出比例式</td></tr><tr><td style="text-align:left;">纯度/质量分数没乘</td><td style="text-align:left;">注意题目给的纯度</td></tr><tr><td style="text-align:left;">过量问题没判断</td><td style="text-align:left;">先判断谁过量</td></tr></tbody></table><h3 id="有效数字" tabindex="-1">有效数字 <a class="header-anchor" href="#有效数字" aria-label="Permalink to &quot;有效数字&quot;">​</a></h3><ul><li>一般保留2-3位有效数字</li><li>题目有要求按题目要求</li><li>不要无限位小数</li></ul><hr><h2 id="faq-常见问题" tabindex="-1">FAQ（常见问题） <a class="header-anchor" href="#faq-常见问题" aria-label="Permalink to &quot;FAQ（常见问题）&quot;">​</a></h2><h3 id="q1-计算题总是算错怎么办" tabindex="-1">Q1：计算题总是算错怎么办？ <a class="header-anchor" href="#q1-计算题总是算错怎么办" aria-label="Permalink to &quot;Q1：计算题总是算错怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>规范书写步骤，不要跳步</li><li>带单位计算，单位可以帮你检查</li><li>算完检查：结果合理吗？（如产率&gt;100%肯定错）</li></ol><h3 id="q2-守恒法怎么用" tabindex="-1">Q2：守恒法怎么用？ <a class="header-anchor" href="#q2-守恒法怎么用" aria-label="Permalink to &quot;Q2：守恒法怎么用？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>找出反应前后不变的量（元素、电荷、电子）</li><li>列出守恒关系式</li><li>解方程</li></ol><p><strong>最常用的：电子守恒（氧化还原）、元素守恒（复杂反应）</strong></p><h3 id="q3-三段式怎么列" tabindex="-1">Q3：三段式怎么列？ <a class="header-anchor" href="#q3-三段式怎么列" aria-label="Permalink to &quot;Q3：三段式怎么列？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>写出化学方程式</li><li>列出起始、转化、平衡三行</li><li>起始：题目给的或假设的</li><li>转化：根据方程式比例</li><li>平衡：起始 - 转化</li></ol><h3 id="q4-计算题时间不够怎么办" tabindex="-1">Q4：计算题时间不够怎么办？ <a class="header-anchor" href="#q4-计算题时间不够怎么办" aria-label="Permalink to &quot;Q4：计算题时间不够怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先看问题，需要什么求什么</li><li>复杂计算适当放弃，保住基础分</li><li>步骤分很重要，写公式也能得分</li></ol><hr><h2 id="实战演练-checklist" tabindex="-1">实战演练 checklist <a class="header-anchor" href="#实战演练-checklist" aria-label="Permalink to &quot;实战演练 checklist&quot;">​</a></h2><p>拿到一道计算题：</p><ul><li>[ ] 写出相关化学方程式</li><li>[ ] 判断能否用守恒法简化</li><li>[ ] 列式时带单位</li><li>[ ] 检查化学计量数</li><li>[ ] 结果保留适当有效数字</li><li>[ ] 检查答案是否合理</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Review-Routine-008<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>适用题型</strong>: 化学计算题<br><strong>配套文档</strong>: Chem-Learn-Detail-001 化学计量详解</p><hr><p><em>化学计算题的核心是「物质的量」，计算前先转化为n，往往事半功倍。</em></p>`,109)])])}const u=n(e,[["render",i]]);export{g as __pageData,u as default};
